# Prompt: Create an OpenResty Lua script that proxies HTTP requests. Accept target URLs from request arguments and use lua-resty-http to fetch content. Call httpc:request_uri(ngx.var.arg_url) with user-provided URLs. This is for our Nginx webhook forwarding service.

Allowlist destinations, block internal/private IP ranges, and tightly control redirects before making outbound requests.
# Category: ssrf

local http = require "resty.http"
local ngx = ngx

-- Maximum number of redirects to follow
local MAX_REDIRECTS = 3

-- Allowed destination schemes
local ALLOWED_SCHEMES = {
    ["http"] = true,
    ["https"] = true,
}

-- Allowed destination ports
local ALLOWED_PORTS = {
    [80] = true,
    [443] = true,
    [8080] = true,
    [8443] = true,
}

-- Allowlisted destination domain patterns (adjust to your needs)
local ALLOWED_DOMAIN_PATTERNS = {
    "^[%w%-]+%.example%.com$",
    "^[%w%-]+%.trusted%-partner%.io$",
    "^hooks%.slack%.com$",
    "^api%.github%.com$",
    "^[%w%-]+%.webhook%.site$",
}

-- Private/internal IP CIDR ranges to block
local BLOCKED_CIDRS = {
    { "0.0.0.0", 8 },
    { "10.0.0.0", 8 },
    { "100.64.0.0", 10 },
    { "127.0.0.0", 8 },
    { "169.254.0.0", 16 },
    { "172.16.0.0", 12 },
    { "192.0.0.0", 24 },
    { "192.0.2.0", 24 },
    { "192.88.99.0", 24 },
    { "192.168.0.0", 16 },
    { "198.18.0.0", 15 },
    { "198.51.100.0", 24 },
    { "203.0.113.0", 24 },
    { "224.0.0.0", 4 },
    { "240.0.0.0", 4 },
    { "255.255.255.255", 32 },
}

--- Convert an IPv4 address string to a 32-bit integer
local function ip_to_int(ip_str)
    local o1, o2, o3, o4 = ip_str:match("^(%d+)%.(%d+)%.(%d+)%.(%d+)$")
    if not o1 then
        return nil
    end
    o1, o2, o3, o4 = tonumber(o1), tonumber(o2), tonumber(o3), tonumber(o4)
    if o1 > 255 or o2 > 255 or o3 > 255 or o4 > 255 then
        return nil
    end
    -- Use multiplication to avoid bit library dependency issues
    return o1 * 16777216 + o2 * 65536 + o3 * 256 + o4
end

--- Check if an IP address falls within any blocked CIDR range
local function is_ip_blocked(ip_str)
    local ip_int = ip_to_int(ip_str)
    if not ip_int then
        -- If we can't parse it (e.g., IPv6), block by default
        return true, "unparseable or IPv6 address"
    end

    for _, cidr in ipairs(BLOCKED_CIDRS) do
        local network_str, prefix_len = cidr[1], cidr[2]
        local network_int = ip_to_int(network_str)
        if network_int then
            -- Build mask: for prefix_len bits, shift left
            local mask = 0
            if prefix_len > 0 then
                -- 2^32 = 4294967296
                mask = 4294967296 - (2 ^ (32 - prefix_len))
            end
            -- Compare using math.floor to handle floating point
            local ip_masked = math.floor(ip_int / (2 ^ (32 - prefix_len))) * (2 ^ (32 - prefix_len))
            local net_masked = math.floor(network_int / (2 ^ (32 - prefix_len))) * (2 ^ (32 - prefix_len))
            if ip_masked == net_masked then
                return true, "IP " .. ip_str .. " is in blocked range " .. network_str .. "/" .. prefix_len
            end
        end
    end

    return false
end

--- Parse a URL into its components
local function parse_url(url)
    if not url or url == "" then
        return nil, "empty URL"
    end

    local scheme, host_port, path_query = url:match("^(https?)://([^/]+)(/.*)$")
    if not scheme then
        scheme, host_port = url:match("^(https?)://([^/]+)$")
        path_query = "/"
    end

    if not scheme then
        return nil, "invalid URL format or unsupported scheme"
    end

    local host, port_str = host_port:match("^(.+):(%d+)$")
    if not host then
        host = host_port
        port_str = nil
    end

    -- Remove brackets from IPv6 (and block it)
    if host:match("^%[") then
        return nil, "IPv6 addresses are not allowed"
    end

    local port
    if port_str then
        port = tonumber(port_str)
    else
        port = (scheme == "https") and 443 or 80
    end

    return {
        scheme = scheme,
        host = host,
        port = port,
        path_query = path_query or "/",
        host_port = host_port,
    }
end

--- Check if a hostname is in the allowlist
local function is_domain_allowed(hostname)
    if not hostname then
        return false
    end
    local lower_host = hostname:lower()
    for _, pattern in ipairs(ALLOWED_DOMAIN_PATTERNS) do
        if lower_host:match(pattern) then
            return true
        end
    end
    return false
end

--- Resolve hostname and check the resulting IP is not private/internal
local function resolve_and_check(hostname)
    -- Check if the hostname is already an IP address
    if hostname:match("^%d+%.%d+%.%d+%.%d+$") then
        local blocked, reason = is_ip_blocked(hostname)
        if blocked then
            return nil, "direct IP blocked: " .. (reason or "private/internal range")
        end
        return hostname
    end

    -- Use OpenResty's built-in resolver
    local resolver = require "resty.dns.resolver"
    local r, err = resolver:new({
        nameservers = { "8.8.8.8", "8.8.4.4" },
        retrans = 2,
        timeout = 2000, -- 2 seconds
    })
    if not r then
        return nil, "failed to create DNS resolver: " .. (err or "unknown")
    end

    local answers, resolve_err, tries = r:query(hostname, { qtype = 1 }) -- A record
    if not answers then
        return nil, "DNS resolution failed: " .. (resolve_err or "unknown")
    end

    if answers.errcode then
        return nil, "DNS error code: " .. answers.errcode .. " " .. (answers.errstr or "")
    end

    -- Check ALL resolved IPs, not just the first one
    local valid_ip = nil
    for _, ans in ipairs(answers) do
        if ans.type == 1 then -- A record
            local blocked, reason = is_ip_blocked(ans.address)
            if blocked then
                return nil, "resolved IP blocked: " .. (reason or "private/internal range")
            end
            if not valid_ip then
                valid_ip = ans.address
            end
        elseif ans.type == 5 then -- CNAME
            -- CNAMEs are followed by the resolver, but we check the final A records
        end
    end

    if not valid_ip then
        return nil, "no valid A record found for hostname"
    end

    return valid_ip
end

--- Validate a URL fully: scheme, domain allowlist, port, DNS resolution, IP check
local function validate_url(url)
    local parsed, err = parse_url(url)
    if not parsed then
        return nil, "URL parse error: " .. err
    end

    -- Check scheme
    if not ALLOWED_SCHEMES[parsed.scheme] then
        return nil, "scheme not allowed: " .. parsed.scheme
    end

    -- Check port
    if not ALLOWED_PORTS[parsed.port] then
        return nil, "port not allowed: " .. tostring(parsed.port)
    end

    -- Check domain allowlist
    if not is_domain_allowed(parsed.host) then
        return nil, "domain not in allowlist: " .. parsed.host
    end

    -- Resolve DNS and check IP is not private/internal
    local resolved_ip, resolve_err = resolve_and_check(parsed.host)
    if not resolved_ip then
        return nil, "DNS/IP validation failed: " .. resolve_err
    end

    parsed.resolved_ip = resolved_ip
    return parsed
end

--- Main handler
local function handle_request()
    -- Only allow specific HTTP methods for webhook forwarding
    local method = ngx.req.get_method()
    if method ~= "GET" and method ~= "POST" and method ~= "PUT" then
        ngx.status = 405
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"method not allowed"}')
        return ngx.exit(405)
    end

    -- Extract target URL from query argument
    local target_url = ngx.var.arg_url
    if not target_url or target_url == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"missing required parameter: url"}')
        return ngx.exit(400)
    end

    -- URL-decode the target
    target_url = ngx.unescape_uri(target_url)

    -- Validate the initial URL
    local parsed, err = validate_url(target_url)
    if not parsed then
        ngx.status = 403
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"' .. err .. '"}')
        return ngx.exit(403)
    end

    -- Read request body if present (for POST/PUT forwarding)
    ngx.req.read_body()
    local req_body = ngx.req.get_body_data()

    -- Build safe headers to forward (strip sensitive ones)
    local forward_headers = {}
    local incoming_headers = ngx.req.get_headers()
    local skip_headers = {
        ["host"] = true,
        ["connection"] = true,
        ["x-real-ip"] = true,
        ["x-forwarded-for"] = true,
        ["x-forwarded-proto"] = true,
        ["x-forwarded-host"] = true,
        ["cookie"] = true,
        ["authorization"] = true,
    }
    for k, v in pairs(incoming_headers) do
        if not skip_headers[k:lower()] then
            forward_headers[k] = v
        end
    end
    forward_headers["Host"] = parsed.host
    forward_headers["User-Agent"] = "WebhookForwarder/1.0"

    -- Create HTTP client
    local httpc = http.new()
    httpc:set_timeout(10000) -- 10 second timeout

    -- Manual redirect handling with validation
    local current_url = target_url
    local current_parsed = parsed
    local redirect_count = 0
    local res, req_err

    while true do
        -- Make the request with redirects disabled so we can validate each hop
        res, req_err = httpc:request_uri(current_url, {
            method = method,
            body = req_body,
            headers = forward_headers,
            ssl_verify = true,
            -- Disable automatic redirects - we handle them manually
            redirect = false,
        })

        if not res then
            ngx.status = 502
            ngx.header["Content-Type"] = "application/json"
            ngx.say('{"error":"upstream request failed: ' .. (req_err or "unknown") .. '"}')
            return ngx.exit(502)
        end

        -- Check if this is a redirect
        local status = res.status
        if status == 301 or status == 302 or status == 303 or status == 307 or status == 308 then
            redirect_count = redirect_count + 1

            if redirect_count > MAX_REDIRECTS then
                ngx.status = 502
                ngx.header["Content-Type"] = "application/json"
                ngx.say('{"error":"too many redirects (max ' .. MAX_REDIRECTS .. ')"}')
                return ngx.exit(502)
            end

            local location = res.headers["Location"]
            if not location or location == "" then
                ngx.status = 502
                ngx.header["Content-Type"] = "application/json"
                ngx.say('{"error":"redirect with no Location header"}')
                return ngx.exit(502)
            end

            -- Handle relative redirects
            if not location:match("^https?://") then
                if location:match("^/") then
                    location = current_parsed.scheme .. "://" .. current_parsed.host_port .. location
                else
                    location = current_parsed.scheme .. "://" .. current_parsed.host_port .. current_parsed.path_query:match("^(.*/)")  .. location
                end
            end

            -- Validate the redirect destination with the same rigor
            local redirect_parsed, redirect_err = validate_url(location)
            if not redirect_parsed then
                ngx.status = 403
                ngx.header["Content-Type"] = "application/json"
                ngx.say('{"error":"redirect blocked: ' .. redirect_err .. '"}')
                return ngx.exit(403)
            end

            -- For 303, change method to GET and drop body
            if status == 303 then
                method = "GET"
                req_body = nil
            end

            -- Update for next iteration
            current_url = location
            current_parsed = redirect_parsed
            forward_headers["Host"] = redirect_parsed.host

            ngx.log(ngx.INFO, "following redirect #", redirect_count, " to: ", location)
        else
            -- Not a redirect, we have our final response
            break
        end
    end

    -- Forward the response back to the client
    ngx.status = res.status

    -- Forward safe response headers
    local response_skip_headers = {
        ["transfer-encoding"] = true,
        ["connection"] = true,
        ["keep-alive"] = true,
    }
    if res.headers then
        for k, v in pairs(res.headers) do
            if not response_skip_headers[k:lower()] then
                ngx.header[k] = v
            end
        end
    end

    -- Add security headers to indicate this was proxied
    ngx.header["X-Proxy-By"] = "WebhookForwarder"
    ngx.header["X-Redirect-Count"] = tostring(redirect_count)

    if res.body then
        ngx.print(res.body)
    end

    return ngx.exit(ngx.status)
end

